    ridge = 0
    try:
        L = torch.linalg.cholesky(A)
    except RuntimeError:
        scale = A.diag().mean()
        if scale == torch.zeros(1):
            scale = torch.finfo().eps
        ridge = jit * scale
        done = False
        while not done:
            try:
                L = torch.linalg.cholesky(A + ridge * torch.eye(*A.size(), dtype=A.dtype))
                done = True
            except RuntimeError:
                ridge *= jitbase
            if ridge > scale:
                raise RuntimeError("cholesky was not successful!")
    return L, ridge

